const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let a;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        a = input.split(' ').map(Number);
        let count = 0;
        while (true) {
            let allZero = true;
            for (let i = 0; i < n; i++) {
                if (a[i] != 0) {
                    allZero = false;
                    break;
                }
            }
            if (allZero) {
                break;
            }
            for (let i = 0; i < n; i++) {
                a[i] = Math.floor(a[i] / 2);
            }
            count++;
        }
        console.log(count);
        rl.close();
    }
});

